#[doc(alias = "checkstrike")]
pub fn CHECKSTRIKE(cpu: &mut Cpu) {
    cpu.set_a(cpu.mem[sym::KidPosn]);
    if cpu.reg.a == 0x00 {
        return;
    }
    if cpu.reg.a >= 0xdb {
        if cpu.reg.a < 0xe5 {
            return;
        }
    }
    crate::ctrlsubs::LOADSHADWOP(cpu);
    TestStrike(cpu);
    crate::ctrlsubs::SAVESHADWOP(cpu);
    crate::ctrlsubs::LOADKIDWOP(cpu);
    TestStrike(cpu);
    crate::ctrlsubs::SAVEKIDWOP(cpu);
    return;
}

pub fn TestStrike(cpu: &mut Cpu) {
    cpu.set_a(cpu.mem[sym::CharSword]);
    if cpu.reg.a != 0x02 {
        return;
    }
    cpu.set_a(cpu.mem[sym::CharBlockY]);
    if cpu.reg.a != cpu.mem[sym::OpBlockY] {
        return;
    }
    cpu.set_a(cpu.mem[sym::CharPosn]);
    match cpu.reg.a {
        0x99 | 0x9a => {
            'b12: {
                crate::ctrlsubs::GETOPDIST(cpu);
                if cpu.reg.a >= 0x00 {
                    if cpu.reg.a < 0x1d {
                        cpu.set_a(cpu.mem[sym::OpPosn]);
                        if cpu.reg.a != 0xa1 {
                            if cpu.reg.a != 0x96 {
                                break 'b12;
                            } else {
                                cpu.set_a(0xa1);
                                cpu.mem[sym::OpPosn] = cpu.reg.a;
                            }
                        }
                        cpu.set_a(cpu.mem[sym::CharID]);
                        if cpu.reg.a != 0x00 {
                            cpu.set_a(0x04);  // yes--impair my blocking ability for a while
                            cpu.mem[sym::justblocked] = cpu.reg.a;
                        }
                        cpu.set_a(0x45);
                        crate::ctrlsubs::JUMPSEQ(cpu);
                        crate::coll::ANIMCHAR(cpu);
                        return;
                    }
                }
            }
            cpu.set_a(cpu.mem[sym::CharPosn]);
            if cpu.reg.a != 0x9a {
                return;
            }
            crate::ctrlsubs::GETOPDIST(cpu);
            cpu.set_x(cpu.mem[sym::OpSword]);
            if cpu.reg.x >= 0x02 {
                if cpu.reg.a < 0x0c {
                    return;
                }
            } else {
                if cpu.reg.a < 0x08 {
                    return;
                }
            }
            if cpu.reg.a >= 0x1d {
                return;
            }
            cpu.set_a(0x63);  // "stabbed"
            cpu.mem[sym::OpAction] = cpu.reg.a;
            return;
        }
        _ => {}
    }
    return;
}

#[doc(alias = "checkstab")]
